#include "kernel_operator.h"
#include <float.h>

constexpr int32_t BUFFER_NUM = 2;

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t rows, uint32_t cols, uint32_t tileLength) {
        rows_ = rows;
        cols_ = cols;
        tileLen_ = tileLength;

        uint32_t rowIdx = AscendC::GetBlockIdx();
        if (rowIdx >= rows_) return;

        xGm_.SetGlobalBuffer((__gm__ float*)x + rowIdx * cols_, cols_);
        yGm_.SetGlobalBuffer((__gm__ float*)y + rowIdx * cols_, cols_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process() {
        if (rows_ == 0u || tileLen_ == 0u) return;

        uint32_t rowIdx = AscendC::GetBlockIdx();
        if (rowIdx >= rows_) return;

        // Process one row: only one tile for simplicity (tileLen_ <= cols_)
        // In a production kernel you would loop over multiple tiles.
        uint32_t len = tileLen_ < cols_ ? tileLen_ : cols_;

        // Load entire tile
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_, len);

        // Compute max
        float maxVal = -FLT_MAX;
        for (uint32_t i = 0; i < len; i++) {
            float val = xLocal(i);
            if (val > maxVal) maxVal = val;
        }

        // Compute sum of exp(x - max)
        float sum = 0.0f;
        for (uint32_t i = 0; i < len; i++) {
            sum += expf(xLocal(i) - maxVal);
        }

        // Compute log-sum and then LSE = max + log(sum)
        float logSum = logf(sum);
        float lse = maxVal + logSum;

        // Compute output: y = x - lse
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        for (uint32_t i = 0; i < len; i++) {
            yLocal(i) = xLocal(i) - lse;
        }

        // Copy output to global
        AscendC::DataCopy(yGm_, yLocal, len);

        // Free resources
        inQueueX_.FreeTensor(xLocal);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t rows_{0};
    uint32_t cols_{0};
    uint32_t tileLen_{0};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
